import{_ as a,a as t,b as n,c as i}from"./chunks/备份成功切换读取源.D8MmJkxg.js";import{_ as d,o as r,c as l,a2 as s}from"./chunks/framework.DnrXFDHb.js";const B=JSON.parse('{"title":"Redundantes Backup und Lesequelle wechseln","description":"","frontmatter":{},"headers":[],"relativePath":"de-DE/Other/redundant-backup-and-read-source.md","filePath":"de-DE/Other/redundant-backup-and-read-source.md","lastUpdated":1781962217000}'),u={name:"de-DE/Other/redundant-backup-and-read-source.md"};function h(c,e,p,o,k,b){return r(),l("div",null,[...e[0]||(e[0]=[s('<h1 id="redundantes-backup-und-lesequelle-wechseln" tabindex="-1">Redundantes Backup und Lesequelle wechseln <a class="header-anchor" href="#redundantes-backup-und-lesequelle-wechseln" aria-label="Permalink to &quot;Redundantes Backup und Lesequelle wechseln&quot;">​</a></h1><p>Das redundante Backup speichert eine zusätzliche Kopie bereits hochgeladener Dateien.</p><p>Für Besucher sehen Hauptdatei und Backup gleich aus. Der Unterschied liegt nur darin, aus welchem Speicherkanal die Datei gelesen wird.</p><h2 id="moglichkeiten" tabindex="-1">Möglichkeiten <a class="header-anchor" href="#moglichkeiten" aria-label="Permalink to &quot;Möglichkeiten&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Funktion</th><th>Beschreibung</th></tr></thead><tbody><tr><td>Zusätzliche Kopie speichern</td><td>Datei in einen anderen Kanal kopieren und Abhängigkeit von einem Speicher reduzieren</td></tr><tr><td>Lesequelle wechseln</td><td>Zwischen Hauptkanal und Backup-Kanal wechseln</td></tr><tr><td>Einzeldatei sichern</td><td>Backup aus der Dateidetailansicht erstellen</td></tr><tr><td>Stapel-Backup</td><td>Mehrere Dateien im Adminbereich auswählen und zusammen sichern</td></tr><tr><td>Globale Ergänzung</td><td>Fehlende Backups ordnerweise unter Weitere Einstellungen ergänzen</td></tr></tbody></table><h2 id="wo-einstellen" tabindex="-1">Wo einstellen <a class="header-anchor" href="#wo-einstellen" aria-label="Permalink to &quot;Wo einstellen&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Systemeinstellungen -&gt; Weitere Einstellungen -&gt; Redundantes Backup</span></span></code></pre></div><p><img src="'+a+'" alt="Redundantes Backup" loading="lazy"></p><p>Hier kannst du Backups für einen bestimmten Ordner oder für alle Dateien ergänzen. Der Backup-Kanal kann manuell gewählt oder automatisch von ImgBed ausgewählt werden.</p><h2 id="backup-aus-der-dateiansicht" tabindex="-1">Backup aus der Dateiansicht <a class="header-anchor" href="#backup-aus-der-dateiansicht" aria-label="Permalink to &quot;Backup aus der Dateiansicht&quot;">​</a></h2><p>Öffne im Adminbereich die Details einer Datei und starte dort das Backup.</p><p><img src="'+t+'" alt="Backup in Dateidetails" loading="lazy"></p><p>Das ist praktisch für einzelne wichtige Dateien. Nach erfolgreichem Backup zeigt die Detailansicht die verfügbaren Lesequellen.</p><h2 id="backup-per-auswahl" tabindex="-1">Backup per Auswahl <a class="header-anchor" href="#backup-per-auswahl" aria-label="Permalink to &quot;Backup per Auswahl&quot;">​</a></h2><p>Im Adminbereich kannst du mehrere Dateien auswählen und ein Stapel-Backup starten.</p><p><img src="'+n+'" alt="Stapel-Backup" loading="lazy"></p><p>Backup aus Details, Backup per Auswahl und redundantes Backup unter Weitere Einstellungen nutzen dieselbe Logik; nur der Einstieg ist anders.</p><h2 id="lesequelle-wechseln" tabindex="-1">Lesequelle wechseln <a class="header-anchor" href="#lesequelle-wechseln" aria-label="Permalink to &quot;Lesequelle wechseln&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Quelle</th><th>Beschreibung</th></tr></thead><tbody><tr><td>Hauptkanal</td><td>Liest aus dem ursprünglichen Upload-Kanal</td></tr><tr><td>Backup-Kanal</td><td>Liest aus dem Kanal, in dem die Kopie gespeichert wurde</td></tr></tbody></table><p><img src="'+i+'" alt="Lesequelle wechseln" loading="lazy"></p><p>Nach dem Wechsel funktionieren Bilder, Videos und Download-Links wie gewohnt mit der gewählten Quelle.</p><h2 id="ubersprungene-falle" tabindex="-1">Übersprungene Fälle <a class="header-anchor" href="#ubersprungene-falle" aria-label="Permalink to &quot;Übersprungene Fälle&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Fall</th><th>Grund</th></tr></thead><tbody><tr><td>Backup existiert bereits</td><td>Verhindert unnötige doppelte Speicherung</td></tr><tr><td>Haupt- und Backup-Kanal sind gleich</td><td>Kopie im selben Kanal bringt keine Redundanz</td></tr><tr><td>Kein Kanal verfügbar</td><td>Es wurde kein geeigneter anderer Kanal gefunden</td></tr></tbody></table><h2 id="beim-loschen" tabindex="-1">Beim Löschen <a class="header-anchor" href="#beim-loschen" aria-label="Permalink to &quot;Beim Löschen&quot;">​</a></h2><p>Beim Löschen einer Datei entfernt ImgBed sowohl die Hauptdatei als auch die Backup-Kopie.</p>',25)])])}const w=d(u,[["render",h]]);export{B as __pageData,w as default};
